+{"type":"message","timestamp":"2025-12-01T10:01:12Z","message":{"role":"assistant","content":"Here's the JWT token generation module:

```rust
use jsonwebtoken::{encode, Header, EncodingKey};
use serde::{Serialize, Deserialize};

#[derive(Serialize, Deserialize)]
struct Claims {
    sub: String,
    exp: usize,
    iat: usize,
}

pub fn generate_token(user_id: &str, secret: &[u8]) -> Result<String, Error> {
    let now = chrono::Utc::now().timestamp() as usize;
    let claims = Claims {
        sub: user_id.to_string(),
        exp: now + 3600,
        iat: now,
    };
    encode(&Header::default(), &claims, &EncodingKey::from_secret(secret))
}
